return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'bg_BG','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Моля, актуализирайте приставката TranslatePress - Multilingual до версия %1$s или по-висока, за да работи %2$s правилно.','Please install and activate the TranslatePress - Multilingual plugin'=>'Моля, инсталирайте и активирайте приставката TranslatePress - Multilingual','Install & Activate'=>'Инсталиране и активиране','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Моля, актуализирайте TranslatePress - Multilingual до версия %2$s или по-нова. Инсталираната в момента версия на TranslatePress - Multilingual вече не е съвместима с текущата версия на %1$s.','All TranslatePress functionalities are disabled until then.'=>'Всички функционалности на TranslatePress са изключени до тогава.','Update Now'=>'Актуализирайте сега','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Тази добавка за TranslatePress е прехвърлена към основната приставка и вече не се използва. Можете да я изтриете.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> изисква поне PHP версия 5.6.20+, за да работи. Това е <a href="%s">минималното изискване на най-новата версия на WordPress</a>. Моля, свържете се с администратора на сървъра ви, за да актуализира PHP версията ви.','Advanced'=>'Разширени','Settings saved.'=>'Настройките са запазени.','Are you sure you want to remove this item?'=>'Сигурни ли сте, че искате да премахнете този елемент?','Remove'=>'Премахване','Add'=>'Добавяне','Select...'=>'Изберете...','[%s] Low TranslatePress AI Words'=>'[%s] Малко думи за TranslatePress AI','upgrade your plan or get extra AI Words'=>'надградете плана си или получете допълнителни AI думи','upgrade your plan'=>'надградете плана си','TranslatePress AI words are running low on your site.'=>'Думите за TranslatePress AI на вашия сайт свършват.','Current status: %s words remaining'=>'Текущо състояние: %s оставащи думи','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'След като оставащите AI думи свършат, автоматичният превод чрез TranslatePress AI ще бъде поставен на пауза.','To continue translating your content, please %1$s over at %2$s'=>'За да продължите с превода на съдържанието си, моля %1$s в %2$s','Manage Notification: %s'=>'Управление на известията: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Налична е нова версия на %1$s. %2$sВижте подробности за версия %3$s%4$s или %5$sобновете сега%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Налична е нова версия на %1$s. %2$sВижте подробности за версия %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'За да активирате обновяванията, моля %1$sвъведете лицензния си ключ%2$s. Нуждаете се от лицензен ключ? %3$sЗакупете такъв сега%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'За да активирате обновяванията, моля отидете на %1$sстраницата за лиценз%2$s и проверете дали имате валиден лиценз.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'За да активирате обновяванията, лицензът ви трябва да бъде подновен. Моля, отидете на страницата %1$sTranslatePress Account%2$s и влезте, за да го подновите.','You do not have permission to install plugin updates'=>'Нямате права да инсталирате актуализации на приставки','Error'=>'Грешка','Your TranslatePress license key is invalid or missing.'=>'Вашият лицензен ключ за TranslatePress е невалиден или липсва.','Your license key expired on %s.'=>'Лицензният ви ключ изтече на %s.','Your license key has been disabled.'=>'Лицензният ви ключ е деактивиран.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Лицензният ви ключ е деактивиран за този URL. Активирайте го отново от <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Управление на сайтове.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Несъответствие на лицензния ключ.</strong> Въведеният от вас лиценз не съответства на инсталираната от вас версия на TranslatePress.</p><p>Моля, проверете дали сте инсталирали правилната версия за вашия лиценз от вашия TranslatePress Account.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Ако сте инсталирали само безплатната приставка, но сте добавили платен лиценз, моля инсталирайте платената приставка от вашия TranslatePress Account.','Your license key has reached its activation limit.'=>'Лицензният ви ключ достигна лимита си за активиране.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Надстройте своя план, за да добавите още сайтове. %1$sНадстройте сега%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Този уебсайт вече е активиран с безплатен лиценз. Всеки уебсайт може да използва само един безплатен лиценз.','An error occurred, please try again.'=>'Възникна грешка, моля опитайте отново.','You have successfully activated your license'=>'Успешно активирахте лиценза си.','Others'=>'Други','Restrict by Language'=>'Ограничаване по език','Exclude from Language'=>'Изключване от език','Restrict element to language'=>'Ограничаване на елемента до език','Show this element only in one language.'=>'Показвайте този елемент само на един език.','Enable translation'=>'Разрешаване на превода','Allow translation to the corresponding language only if the content is written in the default language.'=>'Разрешава превода на съответния език само ако съдържанието е написано на езика по подразбиране.','Select language'=>'Избор на език','Choose in which language to show this element.'=>'Изберете на кой език да се показва този елемент.','Exclude element from language'=>'Изключване на елемента от език','Exclude this element from specific languages.'=>'Изключете този елемент от определени езици.','Select languages'=>'Избор на езици','Choose from which languages to exclude this element.'=>'Изберете от кои езици да се изключи този елемент.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Този елемент ще продължи да бъде видим, когато превеждате уебсайта си чрез Редактора на преводи.','The content of this element should be written in the default language.'=>'Съдържанието на този елемент трябва да бъде написано на езика по подразбиране.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> откри SQL грешки. <a href="%s" title="View TranslatePress SQL Errors">Вижте грешките</a>.','Automatic translation has been disabled.'=>'Автоматичният превод е деактивиран.','Dismiss this notice.'=>'Отхвърлете това известие.','Logged errors'=>'Регистрирани грешки','These are the most recent 5 errors logged by TranslatePress:'=>'Това са последните 5 грешки, регистрирани от TranslatePress:','Yes'=>'Да','Why are these errors occuring'=>'Защо възникват тези грешки','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Ако TranslatePress открие нещо нередно при изпълнение на заявки във вашата база данни, може да деактивира функцията Автоматичен превод, за да избегне допълнително таксуване от Google/DeepL. След като разрешите проблемите, Автоматичният превод трябва да се активира ръчно.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Откритите SQL грешки могат да възникнат по различни причини, включително липсващи таблици, липса на права за SQL потребителя да създава таблици или да извършва други операции, проблеми след миграция на сайта или промени в конфигурацията на SQL сървъра.','What you can do in this situation'=>'Какво можете да направите в тази ситуация','Plan A.'=>'План А.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Отидете в Настройки -> TranslatePress -> раздел Общи и запазете настройките. Това ще регенерира таблиците, използвайки текущите ви SQL настройки. Проверете дали не възникват повече грешки, докато разглеждате уебсайта си на преведен език. Погледнете времевите отметки на грешките, за да сте сигурни, че не виждате старите грешки. Показват се само най-скорошните 5 грешки.','Plan B.'=>'План Б.','If your problem isn\'t solved, try the following steps:'=>'Ако проблемът ви не е решен, опитайте следните стъпки:','Create a backup of your database'=>'Създайте резервно копие на вашата база данни','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Създайте копие на всяка таблица за превод, в която срещате грешки. Можете да копирате таблицата в същата база данни (например trp_dictionary_en_us_es_es_COPY) -- изпълнете тази стъпка само ако искате да запазите текущите преводи','Remove the trouble tables by executing the DROP function on them'=>'Премахнете проблемните таблици, като изпълните функцията DROP върху тях','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Отидете в Настройки -> TranslatePress -> раздел Общи и запазете настройките. Това ще регенерира таблиците, използвайки текущия ви SQL сървър.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Копирайте съответното съдържание от дублираните таблици (например trp_dictionary_en_us_es_es_COPY) в новосъздадената таблица (trp_dictionary_en_us_es_es) -- изпълнете тази стъпка само ако искате да запазите текущите преводи','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Тествайте, за да видите дали всичко работи. Ако нещо се обърка, можете да възстановите резервното копие, което сте направили на първата стъпка. Проверете дали не възникват повече грешки, докато разглеждате уебсайта си на преведен език. Погледнете времевите отметки на грешките, за да сте сигурни, че не виждате старите грешки. Показват се само най-скорошните 5 грешки.','Plan C.'=>'План В.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Ако проблемът ви все още не е решен, опитайте се да попитате хостинга си за грешките. Най-честата причина е липса на права за SQL потребителя, като например правото за създаване на таблици.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Неуспешна инсталация. Опитайте отново от <a href="%s" >Таблото с плъгини.</a>','Active'=>'Активен','Permission denied.'=>'Нямате разрешение.','Invalid nonce.'=>'Невалиден nonce.','Settings scope unknown.'=>'Неизвестен обхват на настройките.','Legacy disabled.'=>'Наследеният режим е изключен.','Language Switcher'=>'Превключвател на езика','Change language to %s'=>'Промяна на езика на %s','Automatic Translation'=>'Автоматичен превод','DeepL'=>'DeepL','Unsupported languages'=>'Неподдържани езици','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Избраният двигател за автоматичен превод не поддържа тези езици.<br>Можете все пак ръчно да превеждате страници на тези езици чрез Редактора на преводи.','API key validation failed.'=>'Валидацията на API ключа не беше успешна.','API key verification was successful.'=>'Верификацията на API ключа беше успешна.','Please enter your Google Translate key.'=>'Моля, въведете ключа си за Google Translate.','Please enter your DeepL API key.'=>'Моля, въведете вашия DeepL API ключ.','Not TranslatePress onboarding page.'=>'Не е страница за първоначална настройка на TranslatePress.','Step %s does not exist'=>'Стъпка %s не съществува','Welcome'=>'Добре дошли','Add Languages'=>'Добавяне на езици','Enable Addons'=>'Активиране на добавки','Finalize'=>'Завършване','Exit Setup'=>'Изход от настройката','Upgrade'=>'Надграждане','Nothing here'=>'Няма нищо тук','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Вашият <strong>TranslatePress</strong> лиценз липсва или е невалиден. <br/>Моля, %1$sрегистрирайте копието си%2$s, за да активирате автоматичния превод на уебсайта чрез TranslatePress AI, премиум добавки, автоматични актуализации и поддръжка. Нуждаете се от лицензен ключ? %3$sКупете такъв сега%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Вашият <strong>TranslatePress</strong> лиценз изтича на %1$s. Моля, %2$sПодновете лиценза си%3$s, за да продължите да получавате достъп до автоматични преводи чрез TP AI, премиум добавки, изтегляния на продукти и автоматични актуализации. %4$sПодновете сега%5$s','Error: '=>'Грешка: ','Something went wrong, please try again.'=>'Нещо се обърка, моля, опитайте отново.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Вашият <strong>TranslatePress</strong> лиценз е изтекъл. <br/>Моля, %1$sПодновете лиценза си%2$s, за да продължите да получавате достъп до автоматични преводи чрез TranslatePress AI, премиум добавки, изтегляния на продукти и автоматични актуализации. %3$sПодновете сега %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Несъответствие на лицензния ключ. Въведеният от вас лиценз не съответства на инсталираната <strong>%1$s</strong> версия. <br/>Моля, проверете дали сте инсталирали правилната версия за вашия лиценз от %2$sакаунта си в TranslatePress%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Ако сте инсталирали само безплатната приставка, но сте добавили платен лиценз, моля, инсталирайте платената приставка от вашия акаунт в TranslatePress.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Достигнахте лимита за активиране на вашия <strong>%1$s</strong> лиценз. <br/>Управлявайте активните си сайтове от %2$s вашия акаунт %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Вашият лиценз е деактивиран за този URL. Повторно го активирайте от <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Управление на сайтове.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'Автоматичният превод с %1$s изисква активен лиценз. Моля, %2$sподновете%3$s лиценза си или закупете нов %4$sоттук%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Моля, %1$sвъведете%2$s лицензния си ключ, за да активирате автоматичния превод с %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Остават ви по-малко от 5 000 думи за TranslatePress AI. За да продължите автоматичния превод на уебсайта си, моля, %sзакупете допълнителни AI думи с отстъпка от вашия акаунт%s.',' Error: '=>' Грешка: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Този уебсайт вече е активиран с безплатен лиценз. Всеки уебсайт може да използва само един безплатен лиценз. Моля, надградете до премиум план за повече думи за TranslatePress AI от %1$s вашия акаунт %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Нямате валиден лиценз за <strong>TranslatePress</strong>. %1$sПолучете такъв безплатно%2$s, за да получите достъп до TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>НОВО:</strong> Добавката <strong>Различен домейн за всеки език</strong> вече е тук! Подобрете глобалното си SEO и създайте локално изживяване с домейни специфични за държави като .de или .fr. Надградете до <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business или Developer</a>, за да получите достъп до нея + още премиум привилегии!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>НОВО:</strong> Добавката <strong>Различен домейн за всеки език</strong> вече е тук! Подобрете глобалното си SEO и създайте локално изживяване с домейни специфични за държави като .de или .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Научете повече</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Дневната квота за символи за машинен превод е надвишена. Моля, проверете страницата <strong>TranslatePress -> <a href="%s">Автоматичен превод</a></strong> за повече информация.','Marketing optin'=>'Маркетингово съгласие','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Съгласете се да получавате известия за актуализации по сигурността и функциите, както и за нечувствително диагностично проследяване.','TranslatePress Preferred User Language'=>'Предпочитан потребителски език в TranslatePress','Preferred language to navigate the site'=>'Предпочитан език за навигиране в сайта','The language is automatically set based by the last visited language by the user.'=>'Езикът се задава автоматично въз основа на последния посетен от потребителя език.','Always use this language'=>'Винаги да се използва този език','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'При отметване на тази настройка предпочитаният език ще остане избраният по-горе, без възможност да бъде променян от публичната част.<br>Този език ще се използва при различни операции, като например изпращане на имейл до потребителя.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Здравейте! Изглежда, че от известно време използвате <strong>TranslatePress</strong>, за да преведете своя уебсайт. Това е страхотно! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Ако можете да отделите малко време, за да ни оцените в WordPress.org, ще ни помогнете много (и ще повишите мотивацията ми).','~ Razvan, developer of TranslatePress'=>'~ Razvan, разработчик на TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Оценете TranslatePress на страницата на приставката в WordPress.org','Ok, I will gladly help!'=>'Добре, с удоволствие ще помогна!','No, thanks.'=>'Не, благодаря.','Full Language Names'=>'Пълни имена на езиците','Short Language Names'=>'Кратки имена на езиците','Flags with Full Language Names'=>'Знамена с пълни имена на езиците','Flags with Short Language Names'=>'Знамена с кратки имена на езиците','Only Flags'=>'Само знамена','Full Language Names No HTML'=>'Пълни имена на езиците без HTML','Bottom Right'=>'Долу вдясно','Bottom Left'=>'Долу вляво','Top Right'=>'Горе вдясно','Top Left'=>'Горе вляво','Dark'=>'Тъмна','Light'=>'Светла','Deactivate'=>'Деактивиране','Activate'=>'Активиране','Invalid language code. Please try again.'=>'Невалиден езиков код. Моля, опитайте отново.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Езиковите кодове могат да съдържат само символите A-Z a-z 0-9 - _. Проверете езиковите си кодове в Общите настройки на TranslatePress.','Error! Duplicate URL slug values.'=>'Грешка! Дублирани стойности на URL slug.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Не можете да изберете два езика, които имат един и същ <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">ISO код</a>, но различна формалност, защото това ще доведе до дублирани <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang тагове</a>.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Открит е дублиран език.<br>Всеки език може да бъде добавен само веднъж, за да се осигури точно управление на преводите.<br> Моля, променете дублирания езиков запис и опитайте отново. ','Current Language'=>'Текущ език','Opposite Language'=>'Противоположен език','General'=>'Общи','Translate Site'=>'Преведи сайта','Addons'=>'Добавки','License'=>'Лиценз','Settings'=>'Настройки','Activate License'=>'Активиране на лиценза','Pro Features'=>'Професионални функции','Need Help?'=>'Нуждаете се от помощ?','Recent community discussions'=>'Последни дискусии в общността','Loading...'=>'Зареждане...','Unable to load forum posts'=>'Неуспешно зареждане на публикации във форума','Ask a Question'=>'Задайте въпрос','View All Topics'=>'Вижте всички теми','by'=>'от','Have a question?'=>'Имате въпрос?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Получете помощ директно от разработчиците на приставката, предложете подобрения или споделете обратната си връзка!','Tip for faster help:'=>'Съвет за по-бърза помощ:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Включете какво сте опитали, какво сте очаквали и какво се е случило. Снимките на екрана помагат!','Toggle support chat'=>'Превключване на чата за поддръжка','Ask the community'=>'Попитайте общността','Close'=>'Затвори','Empty feed response'=>'Празен отговор от емисията','Unable to parse feed'=>'Неуспешно анализиране на емисията','Just now'=>'Току-що','%d hour ago'=>'преди %d час' . "\0" . 'преди %d часа','%d day ago'=>'преди %d ден' . "\0" . 'преди %d дни','Source'=>'Източник','Srcset'=>'Srcset','Alt attribute'=>'Атрибут alt','Title attribute'=>'Атрибут title','Anchor link'=>'Котва','Placeholder attribute'=>'Атрибут placeholder','Submit attribute'=>'Атрибут submit','Text'=>'Текст','Video Poster'=>'Постер на видео','plural form'=>'множествена форма','one'=>'едно','few'=>'няколко','many'=>'много','other'=>'друго','Saved'=>'Запазено','Save'=>'Запазване','Saving translation...'=>'Запазване на превода...','You have unsaved changes!'=>'Имате незапазени промени!','Discard changes'=>'Отхвърляне на промените','Discard All'=>'Отхвърляне на всички','Loading Strings...'=>'Зареждане на низове...','Select string to translate...'=>'Изберете низ за превод...','Close Editor'=>'Затвори редактора','From'=>'От','To'=>'На','Add Media'=>'Добави медия','Other languages'=>'Други езици','Context'=>'Контекст','View Website As'=>'Преглед на сайта като','Available in our Pro Versions'=>'Достъпно в нашите Pro версии','Select or Upload Media'=>'Избор или качване на медия','Use this media'=>'Използвай тази медия','Translate'=>'Преведи','Translate entire block element'=>'Преведи целия блоков елемент','Split block to translate strings individually'=>'Разделете блока, за да преведете низовете поотделно','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Запази промените в превода. Бърз клавиш: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Навигирайте към следващия низ в падащия списък. Бърз клавиш: CTRL(⌘) + ALT + Стрелка надясно','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Навигирайте към предишния низ в падащия списък. Бърз клавиш: CTRL(⌘) + ALT + Стрелка наляво','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Отхвърли всички промени. Бърз клавиш: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Отхвърли промените в това текстово поле. За да отхвърлиш промените във всички текстови полета, използвай бързия клавиш: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Отхвърли подсказката','Quick Intro'=>'Бързо въведение','Are you sure you want to split this phrase into smaller parts?'=>'Сигурни ли сте, че искате да разделите тази фраза на по-малки части?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Този низ все още не е готов за превод. <br>Опитайте отново след малко...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'За да работи тази опция, моля актуализирайте добавката Browse as other role до най-новата версия.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'За да превеждате slug-ове, моля актуализирайте добавката SEO Pack до последната версия.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Можете да добавите нов език от <a href="%s">Настройки->TranslatePress</a>','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Все пак можете да използвате TranslatePress, за да <strong style="background: #f5fb9d;">променяте Gettext низове</strong>, налични на вашата страница.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Низовете, създадени от потребителя, не могат да бъдат променяни, само тези от теми и добавки.','Extra Translation Features'=>'Допълнителни функции за превод','Support for 130+ Extra Languages'=>'Поддръжка на 130+ допълнителни езика','Access to TranslatePress AI'=>'Достъп до TranslatePress AI','Translate SEO Title, Description, Slug'=>'Преведете SEO заглавие, описание, Slug','Publish only when translation is complete'=>'Публикуване само когато преводът е завършен','Translate by Browsing as User Role'=>'Превеждане чрез разглеждане като потребителска роля','Different Menu Items for each Language'=>'Различни елементи от менюто за всеки език','Automatic User Language Detection'=>'Автоматично откриване на езика на потребителя','Upgrade to PRO'=>'Надграждане до PRO','Upgrade to PRO with our biggest discount of the year!'=>'Надграждане до PRO с най-голямата ни отстъпка за годината!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'Този Черен петък получете достъп до тези функции и още на част от цената:','No available suggestions'=>'Няма налични предложения','Suggestions from translation memory'=>'Предложения от паметта за превод','Click to Copy'=>'Кликнете за копиране','Human Translation'=>'Човешки превод','Machine Translation'=>'Машинен превод','Text on this page is %s% translated into all languages.'=>'Текстът на тази страница е %s% преведен на всички езици.','%1$s% of text on this page is translated into %2$s.'=>'%1$s% от текста на тази страница е преведен на %2$s.','This page is %1$s% translated into %2$s.'=>'Тази страница е %1$s% преведена на %2$s.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'Slug-ът, който се опитвате да редактирате, е наличен в други типове slug-ове:%s%. Редактирането му ще замени всяко срещане, независимо от текущия тип.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Посочете с мишката произволен текст на страницата, кликнете върху %s,<br> след което променете превода в страничната лента.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'Не забравяйте да запазите превода. Използвайте клавишната комбинация CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Сменете езика, за да видите промените в превода директно на страницата.','Search for any text in this page in the dropdown.'=>'Търсете произволен текст на тази страница в падащото меню.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Вашият %s лиценз е <span class="trp-license-status-emphasized">изтекъл</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Моля, подновете лиценза си, за да продължите да получавате достъп до TranslatePress AI, премиум добавки, автоматични актуализации и поддръжка.','Renew Now'=>'Подновете сега','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Този Черен петък подновете лиценза си на специална цена</strong>, за да продължите да получавате достъп до изтегляния на продукти, автоматични актуализации и поддръжка.','Get Deal'=>'Вземете офертата','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Вашият %s лиценз беше <span class="trp-license-status-emphasized">възстановен</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Моля, закупете нов лиценз, за да продължите да получавате достъп до TranslatePress AI, премиум добавки, автоматични актуализации и поддръжка.','Purchase a new license'=>'Закупете нов лиценз','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Вашият %s лиценз е <span class="trp-license-status-emphasized">липсващ или невалиден</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Моля, въведете валиден лиценз, за да получите достъп до TranslatePress AI, премиум добавки, автоматични актуализации и поддръжка. Нуждаете се от лицензен ключ? %1$sЗакупете сега%2$s','Enter a valid license'=>'Въведете валиден лиценз','Slugs'=>'Slug-ове','Meta Information'=>'Мета информация','String List'=>'Списък с низове','Gettext Strings'=>'Gettext низове','Images'=>'Изображения','Videos'=>'Видеоклипове','Audios'=>'Аудиозаписи','Dynamically Added Strings'=>'Динамично добавени низове','Translation Editor'=>'Редактор на преводи','Edit translations by visually selecting them on each site page'=>'Редактирайте преводите, като ги избирате визуално на всяка страница от сайта','String Translation'=>'Превод на низове','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'Редактирайте преводи на URL slug-ове, добавки и теми (имейли, формуляри и др.)','Current User'=>'Текущ потребител','Logged Out'=>'Излязъл','Translate Page'=>'Преведи страницата','Add a New Language'=>'Добавете нов език','Get a Free AI License'=>'Получете безплатен AI лиценз','Your License is Invalid'=>'Вашият лиценз е невалиден','Get More AI Words (%d left)'=>'Получете още AI думи (остават %d)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Отваря публикацията в редактора за превод. Публикацията трябва предварително да бъде запазена като чернова или публикувана.','Security check'=>'Проверка за сигурност','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>Внимание:</strong> Някои низове съдържат възможно неправилно кодирани знаци. Това може да доведе до повреждане на заявките и страницата да не се превежда в реален режим. Прегледайте следните низове или начина им на извеждане.','TranslatePress data update'=>'Обновяване на данните на TranslatePress','We need to update your translations database to the latest version.'=>'Трябва да актуализираме базата данни с вашите преводи до най-новата версия.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'Актуализирането ще позволи редактиране на преводите на локализиран текст от приставки и тема. Съществуващите преводи ще продължат да работят както досега.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'ВАЖНО: Силно се препоръчва първо да направите резервно копие на базата данни!
Сигурни ли сте, че искате да продължите?','Run the updater'=>'Стартирайте актуализатора','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'Актуализирането ще позволи редактиране на преводите на slug-овете. Съществуващият превод ще продължи да работи както досега.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Моля, активирайте SEO добавката от <br/>WordPress -> Настройки -> TranslatePress -> раздел Добавки','Go to Addons'=>'Към добавките','The SEO Pack add-on allows translation of all the URL slugs:'=>'Добавката SEO Pack позволява превод на всички URL slug-ове:','Taxonomy slugs'=>'Slug-ове на таксономии','Term slugs'=>'Slug-ове на термини','Post slugs (this includes pages and custom post types)'=>'Slug-ове на публикации (включително страници и персонализирани типове публикации)','Post type base slugs'=>'Базови slug-ове на типове публикации','WooCommerce slugs'=>'WooCommerce slug-ове','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'Добавката SEO Pack е налична във ВСИЧКИ премиум версии на плъгина.','Upgrade to Pro'=>'Надграждане до Pro','Description'=>'Описание','Article Section'=>'Раздел на статията','Article Tag'=>'Етикет на статията','OG Title'=>'OG заглавие','OG Site Name'=>'OG име на сайта','OG Description'=>'OG описание','OG Image Alt'=>'OG алт. текст на изображението','Twitter Title'=>'Twitter заглавие','Twitter Description'=>'Twitter описание','Twitter Image Alt'=>'Twitter алт. текст на изображението','Page Title'=>'Заглавие на страницата','Dublin Core Title'=>'Dublin Core заглавие','Dublin Core Description'=>'Dublin Core описание','OG Image'=>'OG изображение','OG Image Secure URL'=>'OG защитен URL на изображение','Twitter Image'=>'Twitter изображение','Removing cdata dictionary strings for language %s...'=>'Премахване на cdata низове от речника за език %s...','Removing untranslated dictionary links for language %s...'=>'Премахване на непреведени връзки от речника за език %s...','Removing duplicated gettext strings for language %s...'=>'Премахване на дублирани Gettext низове за език %s...','Removing duplicated dictionary strings for language %s...'=>'Премахване на дублирани низове от речника за език %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'Премахване на непреведени низове от речника, за които е наличен превод за език %s...','Inserting original strings for language %s...'=>'Вмъкване на оригинални низове за език %s...','Cleaning original strings table for language %s...'=>'Изчистване на таблицата с оригинални низове за език %s...','Updating original string ids for language %s...'=>'Актуализиране на идентификаторите на оригиналните низове за език %s...','Regenerating original meta table for language %s...'=>'Регенериране на таблицата с оригинални метаданни за език %s...','Cleaning original meta table for language %s...'=>'Почистване на таблицата с оригинални метаданни за език %s...','Replacing original id NULL with value for language %s...'=>'Заместване на оригинално ID NULL със стойност за език %s...','Inserting gettext original strings for language %s...'=>'Вмъкване на оригинални Gettext низове за език %s...','Cleaning gettext original strings table for language %s...'=>'Изчистване на таблицата с оригинални Gettext низове за език %s...','Updating gettext original string ids for language %s...'=>'Актуализиране на идентификаторите на оригиналните Gettext низове за език %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'Мигриране на slug-овете на таксономиите и базовите slug-ове на типовете публикации към нова структура на таблицата...','Migrating post slugs to new table structure for language %s...'=>'Мигриране на slug-овете на публикациите към нова структура на таблицата за език %s...','Migrating term slugs to new table structure for language %s...'=>'Мигриране на slug-ове на термини към нова таблична структура за език %s...','Finishing up...'=>'Завършване...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'Оптимизацията на базата данни не завърши успешно. Препоръчваме да възстановите оригиналната база данни или <a href="%s" >да опитате отново.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'Обновяването е прекратено! Вашият потребителски акаунт няма правомощието да извършва обновявания на базата данни.','Update aborted! Invalid nonce.'=>'Обновяването е прекратено! Невалиден nonce.','Update aborted! Incorrect action.'=>'Обновяването е прекратено! Неправилно действие.','Update aborted! Incorrect language code.'=>'Обновяването е прекратено! Неправилен езиков код.','Updating database to version %s+'=>'Обновяване на базата данни до версия %s+','Processing table for language %s...'=>'Обработване на таблицата за език %s...','Back to TranslatePress Settings'=>'Обратно към настройките на TranslatePress','Successfully updated database!'=>'Базата данни е обновена успешно!',' done.'=>' готово.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Всички отделни добавки за TranslatePress <a href="%1$s" target="_blank">са преустановени</a> и вече са включени в премиум версиите Personal, Business и Developer на TranslatePress. Моля, влезте в <a href="%2$s" target="_blank">страницата на акаунта си</a>, изтеглете новата премиум версия и я инсталирайте. Настройките на вашите отделни добавки ще бъдат пренесени.','Brand-new Language Switcher Settings are here!'=>'Съвсем нови настройки за превключвателя на езици са тук!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Разгледайте готови шаблони, променяйте цветове, стилове на знамената, разстояния, оформления и др. Използвайте визуализацията на живо, за да усъвършенствате превключвателя си за секунди.','Start customizing'=>'Започнете персонализирането','Read documentation'=>'Прочетете документацията','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> изисква <strong><a href="http://php.net/manual/en/book.mbstring.php">PHP библиотека за многобайтови низове</a></strong>. Моля, свържете се с администратора на сървъра, за да я инсталира.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'Открито е ограничение за дълги заявки в хостинга на WPEngine. Някои големи страници може да се появят непреведени. Можете да премахнете ограничението, като добавите следното към wp-config.php на вашия сайт: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Потребителско знаме за език','The Language code of the added custom language cannot be empty.'=>'Езиковият код на добавения потребителски език не може да бъде празен.','The Language code of the added custom language is invalid.'=>'Езиковият код на добавения потребителски език е невалиден.','The Automatic Translation Code of the added custom language is invalid.'=>'Кодът за автоматичен превод на добавения потребителски език е невалиден.','TranslatePress Add-ons'=>'Добавки за TranslatePress','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Трябва първо да закупите тази версия, за да имате достъп до добавката %1$sтук%2$s','Please %1$senter your license%2$s key first, to activate this addon.'=>'Моля, първо %1$sвъведете лицензния си%2$s ключ, за да активирате тази добавка.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Нужен ви е активен лиценз, за да имате достъп до добавката. Подновете или закупете нов лиценз %1$sтук%2$s.','Advanced Add-ons'=>'Разширени добавки','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Тези добавки разширяват вашия плъгин за превод и са налични в плановете Developer, Business и Personal.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (Legacy)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'SEO поддръжка за slug на страница, заглавие на страница, описание и информация за социалния граф на Facebook и Twitter. HTML атрибутът lang е зададен правилно.','Multiple Languages'=>'Множество езици','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Добавете толкова езици, колкото ви трябват, за да направите проекта си глобален. Публикувайте езика си само когато всички преводи са готови.','Pro Add-ons'=>'Pro добавки','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Тези добавки разширяват вашия плъгин за превод и са налични в плановете Business и Developer.','DeepL Automatic Translation'=>'Автоматичен превод с DeepL','Automatically translate your website through the DeepL API.'=>'Автоматично превеждайте уебсайта си чрез DeepL API.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Подканва посетителите да превключат към предпочитания от тях език въз основа на настройките на браузъра или IP адреса им и запомня последно посетения език.','Translator Accounts'=>'Акаунти за преводачи','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Създайте акаунти за преводачи за нови потребители или позволете на съществуващи потребители, които не са администратори, да превеждат уебсайта ви.','Browse As User Role'=>'Разглеждане като потребителска роля','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Навигирайте в уебсайта си точно както би го направила конкретна потребителска роля. Много полезно за динамично съдържание или скрито съдържание, което се появява за определени потребители.','Navigation Based on Language'=>'Навигация според езика','Configure different menu items for different languages.'=>'Конфигурирайте различни елементи от менюто за различни езици.','Different Domain per Language'=>'Различен домейн за всеки език','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Свържете отделни домейни или поддомейни към всяка от вашите преведени версии. Укрепете местната идентичност на вашата марка и подобрете SEO представянето за всеки език, който поддържате.','Recommended Plugins'=>'Препоръчани разширения','A short list of plugins you can use to extend your website.'=>'Кратък списък с разширения, които можете да използвате за разширяване на вашия уебсайт.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Събирайте повече информация за потребителите във формуляра за регистрация с помощта на персонализираните полета за потребителски профил на Profile Builder и/или добавете процес за потвърждение по имейл, за да потвърдите акаунтите на вашите клиенти.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Приемайте плащания от потребители, създавайте абонаментни планове и ограничавайте съдържанието във вашия членски сайт.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Създавайте автоматизации и работни процеси без код във вашия WordPress сайт. Свързвайте лесно вашите разширения, сайтове и приложения помежду си.','Save Changes'=>'Запази промените','TranslatePress Errors'=>'Грешки в TranslatePress','There are no logged errors.'=>'Няма записани грешки.','Change language'=>'Смяна на езика','Website language selector'=>'Селектор за език на уебсайта','WordPress Translation Plugin'=>'Разширение за превод на WordPress','Available languages'=>'Налични езици','Language Switcher update notice'=>'Известие за актуализация на превключвателя за език','Legacy language switcher is currently enabled'=>'В момента е активиран старият превключвател за език','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'Подобрихме превключвателя за по-богата персонализация и по-добро потребителско изживяване.<br>За да използвате новия конфигуратор, изключете <strong>Зареждане на стария превключвател за език</strong>.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Забележка: Можете да се върнете по всяко време от <strong>Разширени настройки → <a href="%s">Отстраняване на проблеми</a></strong>.','Enable the new switcher'=>'Активиране на новия превключвател','Your License Key is valid.'=>'Вашият лицензен ключ е валиден.','Your License Key is invalid.'=>'Вашият лицензен ключ е невалиден.','Your License has expired.'=>'Вашият лиценз е изтекъл.','Deactivate License'=>'Деактивиране на лиценза','Add a license key'=>'Добавяне на лицензен ключ','License Key'=>'Лицензен ключ','Manage your license in your %1$s.'=>'Управлявайте лиценза си във вашата %1$s.','Account Page'=>'Страница на акаунта','Don’t have a TranslatePress AI License Key?'=>'Нямате лицензен ключ за TranslatePress AI?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Можете да получите такъв %1$sбезплатно%2$s, като създадете безплатен акаунт. Включва:','Access to TranslatePress AI for instant automatic translations'=>'Достъп до TranslatePress AI за мигновени автоматични преводи','2000 AI words to translate automatically'=>'2000 AI думи за автоматичен превод','Get a free License Today'=>'Получете безплатен лиценз днес','Debug Information'=>'Дебъг информация','Debug Data for License Checking'=>'Дебъг данни за проверка на лиценза','Debug Data for License Activation'=>'Дебъг данни за активиране на лиценза','Get more AI words and unlock all features with TranslatePress Pro.'=>'Получете повече AI думи и отключете всички функции с TranslatePress Pro.','Upgrade now ↗'=>'Надстройте сега ↗','Already purchased a Premium version?'=>'Вече закупихте Премиум версия?','Go to your %1$s'=>'Отидете във вашия %1$s','TranslatePress.com Account'=>'Акаунт в TranslatePress.com','Download & Install the Pro plugin'=>'Изтеглете и инсталирайте Pro добавката','Learn More'=>'Научете повече','Get a translation volume estimate with a detailed breakdown per page'=>'Получете оценка на обема на превода с подробно разбиване по страници','Find how many translatable words are on your website'=>'Разберете колко думи за превод има във вашия уебсайт','Enable Automatic Translation'=>'Активиране на автоматичния превод','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'За да използвате <strong>DeepL</strong> за автоматичен превод, активирайте тази Pro добавка от <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'Автоматичният превод с <strong>DeepL</strong> е наличен като <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'С надграждането ще получите достъп до всички платени добавки, премиум поддръжка и ще помогнете за финансирането на бъдещето развитие на TranslatePress.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Моля, обърнете внимание, че използването на DeepL API се заплаща отделно. Вижте <a href="https://www.deepl.com/pro.html#developer">информация за цените на DeepL</a>.','TranslatePress Pro Add-ons'=>'Добавки на TranslatePress Pro','Test API credentials'=>'Тестване на API идентификационните данни','Check if the selected translation engine is configured correctly.'=>'Проверява дали избраният двигател за превод е конфигуриран правилно.','Alternative Engines'=>'Алтернативни двигатели','Switch to TranslatePress AI'=>'Превключване към TranslatePress AI','Integrate machine translation directly with your WordPress website.'=>'Интегрирайте машинния превод директно с вашия WordPress уебсайт.','More info'=>'Повече информация','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Изберете кой двигател искате да използвате, за да %1$s автоматично преведете вашия уебсайт.','Automatic Translation Settings'=>'Настройки за автоматичен превод','AI Words Low Notification'=>'Известие за малък брой AI думи','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Получавайте имейл известие, когато броят на думите от TranslatePress AI спадне под зададения праг.','This feature is only available when using the TranslatePress AI translation engine.'=>'Тази функция е налична само при използване на преводния механизъм TranslatePress AI.','Notification Email'=>'Имейл за известия','The email address where the low AI words notification will be sent.'=>'Имейл адресът, на който ще бъде изпратено известието за малък брой AI думи.','Word Threshold'=>'Праг за думи','words'=>'думи','You will be notified when remaining AI words drop below this number.'=>'Ще бъдете уведомени, когато останалите AI думи спаднат под това число.','Automatically Translate Slugs'=>'Автоматично превеждане на slug-ове','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Генериране на автоматични преводи на slug-ове за публикации, страници и персонализирани типове публикации.<br/>Slug-овете ще бъдат преведени автоматично, започвайки от второто опресняване на всяка страница.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Тази функция е налична само в платената версия. Надстройте TranslatePress и отключете още премиум функции.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Изисква <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">Добавка SEO Pack</a> да бъде инсталирана и активирана.','Upgrade now'=>'Надстройте сега','Block Crawlers'=>'Блокиране на роботи','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Блокиране на роботите от задействане на автоматични преводи на вашия уебсайт.<br>Това няма да попречи на роботите да достъпват страниците на този сайт.','Limit machine translation / characters per day'=>'Ограничаване на машинния превод / знаци на ден','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Задайте лимит на броя на автоматично преведените знаци, за да планирате по-добре бюджета на проекта си.','characters per day'=>'знаци на ден','Today\'s Character Count: '=>'Брой на знаците за днес: ','Log machine translation queries.'=>'Записвайте заявките за машинен превод.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Активирайте само за тестови цели. Може да повлияе на производителността.<br>Всички записи се съхраняват в таблицата wp_trp_machine_translation_log в базата данни. Използвайте приставка като <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a>, за да разглеждате журналите, или директно от вашия мениджър на бази данни (PHPMyAdmin и т.н.)','Test API Credentials'=>'Тествайте API идентификационните данни','HTTP Referrer: '=>'HTTP референт: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Използвайте този HTTP референт, ако API ви позволява да ограничите използването на ключа от неговото табло за управление.','Response'=>'Отговор','Response Body'=>'Тяло на отговора','Entire Response From wp_remote_get():'=>'Целият отговор от wp_remote_get():','All Languages'=>'Всички езици','Select the languages you wish to make your website available in.'=>'Изберете езиците, на които искате да направите уебсайта си достъпен.','Formality'=>'Формалност','Code'=>'Код','Slug'=>'Slug','Default'=>'По подразбиране','Formal'=>'Формален','Informal'=>'Неформален','Language'=>'Език','This language does not support formality. '=>'Този език не поддържа формалност. ','Are you sure you want to remove this language?'=>'Сигурни ли сте, че искате да премахнете този език?','Custom Languages'=>'Персонализирани езици','To Add more languages activate the Multiple Languages Addon'=>'За да добавите още езици, активирайте добавката Multiple Languages','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Трябва ви активен лиценз, за да добавяте още езици. Проверете във вашия %1$sакаунт%2$s дали лицензът ви е валиден','Please %1$senter your license%2$s key first to add more languages.'=>'Моля, първо %1$sвъведете вашия лиценз%2$s ключ, за да добавяте още езици.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'Добавянето на повече от два езика е платена функция. Надстройте TranslatePress и отключете още премиум функции.','Website Languages'=>'Езици на уебсайта','Default Language'=>'Език по подразбиране','Select the language your content is written in.'=>'Изберете езика, на който е написано вашето съдържание.','WARNING. Changing the default language will invalidate existing translations.'=>'ВНИМАНИЕ. Промяната на езика по подразбиране ще анулира съществуващите преводи.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Дори промяната от en_US на en_GB, защото те се третират като два различни езика.','In most cases changing the default flag is all it is needed: '=>'В повечето случаи е достатъчно да се смени флагът по подразбиране: ','replace the default flag'=>'заменете флага по подразбиране','Re-run Setup Wizard'=>'Пуснете отново съветника за настройка','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'Съветникът за настройка ви позволява бързо да настроите TranslatePress. Можете да го стартирате по всяко време.','Language Settings'=>'Настройки за езика','Use Native language name'=>'Използвайте родното име на езика','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Отметнете, ако искате езиците да се показват с родните им имена. В противен случай, езиците ще се показват на английски.','Use a subdirectory for the default language'=>'Използвайте поддиректория за езика по подразбиране','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Отметнете, ако искате да добавите поддиректорията в URL адреса за езика по подразбиране.</br>С отмятането на тази опция, езикът по подразбиране, който виждат посетителите на уебсайта, ще стане първият в списъка „Всички езици“.','Force language in custom links'=>'Принудително задаване на езика в персонализираните връзки','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Изберете Да, ако искате персонализираните връзки без езиково кодиране да запазват текущо избрания език.','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'Използвайте shortcode на всяка страница или в която и да е джаджа.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'Можете също да добавите <a href="%s" title="Документация за блока за превключване на езика">Блок за превключване на езика</a> в редактора на WP Gutenberg.','Menu item'=>'Елемент от менюто','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Отидете на  %1$s Външен вид -> Менюта%2$s, за да добавите езици към превключвателя на езика в което и да е меню.','Learn more in our documentation.'=>'Научете повече в нашата документация.','Floating language selection'=>'Плаващ избор на език','Add a floating dropdown that follows the user on every page.'=>'Добавете плаващо падащо меню, което следва потребителя на всяка страница.','Show "Powered by TranslatePress"'=>'Показване на "Powered by TranslatePress"','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Показване на малкия надпис "Powered by TranslatePress" в плаващия превключвател на езика.','5 Days to Better Multilingual Websites'=>'5 дни до по-добри многоезични уебсайтове','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sПрисъединете се към нашия БЕЗПЛАТЕН и ЕКСКЛУЗИВЕН въвеждащ курс%s и научете как да увеличите многоезичния си трафик, да достигнете до международни пазари и да спестите време и пари, докато извличате максимума от TranslatePress!','Invalid email address'=>'Невалиден имейл адрес','Your email'=>'Вашият имейл','Sign me up!'=>'Запишете ме!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Регистрирайте се с вашия имейл адрес и получете ръководство по имейл от 5 части, което да ви помогне да извлечете максимума от възможностите на TranslatePress.','Dismiss email course notification'=>'Отхвърли известието за имейл курса','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Здравейте, %s,<br>Не пропускайте важна актуализация — включете се в известията ни за актуализации по сигурността и функциите, както и в диагностичното проследяване без чувствителни данни.','Allow & Continue'=>'Разреши и продължи','Skip'=>'Пропусни','This will allow TranslatePress to:'=>'Това ще позволи на TranslatePress да:','Your profile overview'=>'Преглед на вашия профил','Name and email address'=>'Име и имейл адрес','Admin Notices'=>'Административни известия','Updates, announcements, marketing, no spam'=>'Актуализации, съобщения, маркетинг, без спам','Plugin status & settings'=>'Състояние и настройки на приставката','Active, Deactivated, installed version and settings'=>'Активна, Деактивирана, инсталирана версия и настройки','Privacy Policy'=>'Политика за поверителност','Terms of Service'=>'Условия за ползване','Support'=>'Поддръжка','Documentation'=>'Документация','Add Extra AI Words'=>'Добавяне на допълнителни AI думи','Optimize TranslatePress database tables'=>'Оптимизиране на таблиците в базата данни на TranslatePress','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>ВАЖНА ЗАБЕЛЕЖКА:</strong> Преди извършването на това действие е силно препоръчително първо да направите резервно копие на базата данни.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'ВАЖНО: Силно се препоръчва първо да направите резервно копие на базата данни!! Сигурни ли сте, че искате да продължите?','Operations to perform'=>'Операции за изпълнение','Remove CDATA for original and dictionary strings'=>'Премахване на CDATA за оригинални низове и низове от речника','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Премахва CDATA от таблиците trp_original_strings и trp_dictionary_*.<br>Този тип съдържание не трябва да бъде откриван от TranslatePress. Възможно е да е въведено в базата данни в по-стари версии на приставката.','Remove untranslated links from dictionary tables'=>'Премахване на непреведени връзки от речниковите таблици','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Премахва непреведени връзки и изображения от всички таблици trp_dictionary_*. Тези таблици съдържат преводи за низове, въведени от потребителя, като съдържание на публикация, заглавие на публикация, менюта и т.н.','Remove duplicate rows for gettext strings'=>'Премахване на дублиращи се редове за gettext низове','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Почиства всички таблици trp_gettext_* от дублиращи се редове. Тези таблици съдържат преводи за низове на теми и разширения.','Remove duplicate rows for dictionary strings'=>'Премахване на дублиращи се редове за низове от речника','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Почиства всички таблици trp_dictionary_* от дублиращи се редове. Тези таблици съдържат преводи за низове, въведени от потребителя, като съдържание на публикация, заглавие на публикация, менюта и т.н.','Remove duplicate rows for original dictionary strings'=>'Премахване на дублиращи се редове за оригинални низове от речника','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Почиства таблицата trp_original_strings от дублиращи се редове. Тази таблица съдържа низове на езика по подразбиране, без никакви преводи.<br>Таблицата trp_original_meta, която съдържа метаинформация, отнасяща се до ID на родителската публикация, също се регенерира.<br>Такива дублиращи се редове могат да се появят при изключителни ситуации на неочаквано поведение.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Замяна на gettext низове, чието оригинално ID е NULL, с правилните оригинални ID-та','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Отстранява проблем в граничен случай, при който някои gettext низове имат оригиналното ID зададено неправилно като NULL, което причинява проблеми в Редактора на преводи.<br>Тази операция коригира оригиналните ID-та в таблиците trp_gettext_*.<br>Отметнете тази опция само ако сте срещнали проблем в Редактора на преводи, при който щракването върху зеления молив не показва gettext низа за превод в лявата странична лента.<br>В противен случай моля, оставете тази опция неотметната, защото е интензивна операция.','Optimize Database'=>'Оптимизиране на базата данни','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'Актуализиране на таблиците на TranslatePress. Моля, оставете този прозорец отворен.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'Неактивните езици все още ще бъдат видими и активни за администратора. За други потребители те няма да бъдат видими в превключвателите на езика и няма да бъдат достъпни.','unknown'=>'неизвестно','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Добавка Extra Languages</strong> изисква TranslatePress версия %1$s или по-висока. В момента използвате версия %2$s. Моля, актуализирайте TranslatePress, за да активирате тази функция.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Автоматичните и ръчните промени в превода на slug-ове, извършени при активна версия <strong>TranslatePress - Multilingual</strong> 2.8.4, трябваше да бъдат премахнати поради някои проблеми с тази версия. Всички преводи на slug-ове от преди тази версия вече са в употреба. Благодарим за разбирането!','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Ако абсолютно се нуждаете от тях, премахнатите преводи могат да бъдат намерени в таблиците trp_slug_original_obsolete и trp_slug_translation_obsolete.','View Docs'=>'Виж документацията','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Присвояване на различни домейни или поддомейни на всеки език. Когато посетителите достъпят тези домейни, TranslatePress зарежда директно съответния езиков превод без пренасочване.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Пример: %1$s за английски, %2$s за испански, %3$s за френски.','Before enabling:'=>'Преди активиране:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Уверете се, че домейните ви са регистрирани, насочени към вашия сървър и имат конфигурирани SSL сертификати.','Domain'=>'Домейн','Map this language to a different domain or sub-domain.'=>'Свържете този език с различен домейн или поддомейн.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Попълни с текущия домейн','Check DNS'=>'Проверка на DNS','Checking DNS...'=>'Проверка на DNS...','DNS is correctly configured!'=>'DNS е конфигуриран правилно!','DNS check failed. Please verify your domain configuration.'=>'Проверката на DNS е неуспешна. Моля, проверете конфигурацията на домейна.','This domain is already assigned to another language.'=>'Този домейн вече е зададен на друг език.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Different Domain per Language add-on</strong> изисква TranslatePress версия %1$s или по-висока. В момента използвате версия %2$s. Моля, актуализирайте TranslatePress, за да активирате тази функция.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Забележка: Тази опция е деактивирана, когато добавката Different Domain for Language е активна.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Different Domain per Language: Домейнът е задължителен, когато съпоставянето на домейни е активирано. Превключвателят е деактивиран за езици с празни домейни.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Different Domain per Language: Един и същи домейн не може да бъде зададен на няколко езика. Превключвателят е деактивиран за дублирани домейни.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Different Domain per Language: Домейнът на езика не може да бъде същият като основния URL на сайта. Превключвателят е деактивиран за съвпадащия домейн.','Please enter a domain.'=>'Моля, въведете домейн.','Invalid domain format.'=>'Невалиден формат на домейн.','Could not reach domain: %s'=>'Домейнът е недостъпен: %s','Domain returned HTTP status %d.'=>'Домейнът върна HTTP статус %d.','Domain is reachable!'=>'Домейнът е достъпен!','Limit this menu item to the following languages'=>'Ограничете този елемент от менюто до следните езици','Date format'=>'Формат на датата','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Настройте форматирането на датата за всеки преведен език.<br/>Оставете празно за стандартната настройка на WP или вижте повече информация <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">тук</a>','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'За да редактирате съществуващ език на TranslatePress, въведете кода на езика и попълнете само колоните, които искате да презапишете (напр. Име на езика, Флаг).<br>Можете също да добавяте нови персонализирани езици. Те ще бъдат достъпни в Общи настройки, списъка Всички езици, където може да се редактира URL slug-ът.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'За персонализирано знаме първо качете изображението в медийната библиотека, след което поставете URL.<br>Промяната или изтриването на персонализиран език ще повлияе на преводите и URL адресите на сайта.<br>Кодът на езика и ISO кодът трябва да съдържат само букви, цифри, „-“ и „_“.<br>ISO кодовете могат да бъдат намерени в <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> и <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.','Language code'=>'Код на езика','Language name'=>'Име на езика','Native name'=>'Родно име','ISO Code'=>'ISO код','Flag URL'=>'URL на знамето','Text RTL'=>'RTL текст','Custom language'=>'Персонализиран език','Disable dynamic translation'=>'Изключване на динамичния превод','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Деактивира откриването на низове, показвани динамично чрез JavaScript. <br/>Низовете, заредени чрез сървърна AJAX заявка, все пак ще бъдат преведени.','Disable translation for gettext strings'=>'Деактивиране на превода за gettext низове','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Gettext низовете са низове, извеждани от теми и разширения. <br> Превеждането на тези типове низове чрез TranslatePress може да е ненужно, ако вече са преведени чрез системата за превод с .po/.mo файлове.<br>Активирането на тази опция може да подобри производителността при зареждане на страницата на вашия сайт в определени случаи. Недостатъкът е, че вече няма да можете да редактирате Gettext преводи чрез TranslatePress, нито да се възползвате от автоматичния превод на тези низове.','Gettext Strings translation is disabled'=>'Преводът на Gettext низовете е деактивиран','To enable it go to '=>'За да го активирате, отидете на ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Разширени настройки->Дебъг->Деактивиране на превода за низове на Gettext',' and uncheck the Checkbox.'=>' и премахнете отметката.','Dismiss'=>'Отхвърли','Exclude translated links from sitemap'=>'Изключване на преведените връзки от sitemap','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'Не включвайте преведени връзки в sitemaps, генерирани от SEO плъгини.<br/>Изисква се инсталирането и активирането на <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> Добавка SEO Pack</a>.','Disable post container tags for post title'=>'Изключване на контейнерните етикети за заглавието на публикацията','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Изключва индексирането за търсене на заглавието на публикацията на преведените езици.<br/>Полезно, когато заглавието на публикацията не позволява HTML, което води до повреда на страницата.','Disable post container tags for post content'=>'Изключване на контейнерните етикети за съдържанието на публикацията','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Изключва индексирането за търсене на съдържанието на публикацията на преведените езици.<br/>Полезно, когато съдържанието на публикацията не позволява HTML, което води до повреда на страницата.','Do not translate certain paths'=>'Изключване на определени пътища от превод','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Изберете кои пътища могат да бъдат преведени. Поддържа заместващ символ в края на пътя.<br>Например, за да изключите https://example.com/some/path, можете да използвате правилото /some/path/ или /some/*.<br>Въведете всяко правило на отделен ред. За да изключите началната страница, използвайте {{home}}.','Exclude Paths From Translation'=>'Изключване на пътища от превод','Translate Only Certain Paths'=>'Превод само на определени пътища','Enable the hreflang x-default tag for language:'=>'Активиране на тага hreflang x-default за език:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Активира hreflang="x-default" за цял език. Вижте документацията за повече подробности.','Translate numbers and numerals'=>'Превеждане на числа и цифри','Enable translation of numbers ( e.g. phone numbers)'=>'Активиране на превода на числа ( напр. телефонни номера)','Selector'=>'Селектор','Exclude from dynamic translation'=>'Изключване от динамичен превод','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'Да не се превеждат динамично низове, намерени в HTML възлите, съответстващи на тези селектори.<br>Изключва всички дъщерни елементи на HTML възлите, съответстващи на тези селектори, от превод чрез JavaScript.<br/>Тези низове все пак ще бъдат преведени на сървърно ниво, ако е възможно.','Gettext String'=>'Gettext низ','Exclude Gettext Strings'=>'Изключване на Gettext низове','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Изключете тези низове от превода им като Gettext низове от TranslatePress. Оставете домейна празен, за да се вземат предвид всички Gettext низове.<br/>Все още могат да бъдат преведени чрез po/mo файлове.','Exclude selectors only from automatic translation'=>'Изключване на селектори само от автоматичен превод','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'Да не се превеждат автоматично низове, намерени в HTML възлите, съответстващи на тези селектори.<br>Изключва всички дъщерни елементи на HTML възлите, съответстващи на тези селектори, от автоматичен превод.<br>Ръчният превод на тези низове все още е възможен.','Exclude selectors from translation'=>'Изключване на селектори от превод','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'Да не се превеждат низове, намерени в HTML възлите, съответстващи на тези селектори.<br>Изключва всички дъщерни елементи на HTML възлите, съответстващи на тези селектори, от превод.<br>Тези низове не могат да бъдат преведени нито ръчно, нито автоматично.','String'=>'Низ','Exclude strings from automatic translation'=>'Изключване на низове от автоматичен превод','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'Да не се превеждат автоматично тези низове (напр. имена, технически думи...)<br>Параграфите, съдържащи тези низове, все пак ще бъдат преведени, с изключение на посочената част.','Fix broken HTML'=>'Поправяне на повреден HTML','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Общ опит за поправяне на повреден или липсващ HTML на преведените страници.<br/>','Force slash at end of home url:'=>'Принудително добавяне на наклонена черта в края на home url:','Ads a slash at the end of the home_url() function'=>'Добавя наклонена черта в края на функцията home_url()','Show Both (recommended)'=>'Показване и на двете (препоръчително)','Remove Country Locale'=>'Премахване на локал за държава','Remove Region Independent Locale'=>'Премахване на регионално независим локал','Remove duplicate hreflang'=>'Премахване на дублиран hreflang','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Изберете кои hreflang тагове ще се показват на вашия уебсайт.<br/>Препоръчваме да се показват и двата вида hreflang тагове, както е посочено в <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">документацията на Google</a>.<br/>Премахването на държавната локализация, когато има няколко държавни локализации на един и същ език (напр. English UK и English US), ще доведе до показване на един hreflang таг с връзка само към една от регионалните локализации за този език.','Default (example: en-US, fr-CA, etc.)'=>'По подразбиране (пример: en-US, fr-CA и др.)','Regional (example: en, fr, es, etc.)'=>'Регионален (пример: en, fr, es и др.)','HTML Lang Attribute Format'=>'Формат на HTML Lang атрибута','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Променете lang атрибута на html тага във формат, който включва или не включва държавен регион. <br>В HTML, lang атрибутът (<html lang="en-US">) трябва да се използва за задаване на езика на текстовото съдържание, така че браузърът да може правилно да показва или обработва съдържанието ви (напр. за сричкопренасяне, стилизиране, проверка на правописа и т.н.).','Load legacy Language Switcher'=>'Зареждане на стария превключвател на езика','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'Прилага се за всички типове превключватели на езика (плаващ, shortcode и меню). Когато е активирано, сайтът ще се върне към използването на оригиналния превключвател на езика, конфигуриран в раздела Общи настройки, заменяйки новата персонализируема версия. Вашите съществуващи настройки на превключвателя ще останат запазени, но ще бъдат игнорирани, докато тази опция е активна.','Load legacy SEO Pack Add-On'=>'Зареждане на стария модул SEO Pack','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'В случай че скорошната миграция към новото пренаписване на slug създава проблеми, задайте това на Да, за да използвате стария метод <br> Моля, <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">отворете билет за поддръжка</a>, като ни уведомите за проблемите, които имате.','Manual Translation Only'=>'Само ръчен превод','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress проактивно сканира и запазва низове в базата данни, когато потребителите посещават преведени страници. <br>Тази настройка изключва тази функционалност и позволява превод и запазване на низове само когато сте вътре в Редактора за превод. <br>Също така деактивира машинния превод извън Редактора за превод, което ви дава по-добър контрол върху разхода на символи, като превеждате само страниците, които посещавате в Редактора за превод.','Open language switcher only on click'=>'Отваряне на превключвателя на езика само при кликване','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Отваряне на превключвателя на езика shortcode чрез кликване върху него, вместо със задържане на курсора.<br> Затваряне чрез кликване върху него, някъде другаде на екрана или чрез натискане на клавиша Escape. Това засяга само превключвателя на езика shortcode.','Show opposite language in the language switcher'=>'Показване на противоположния език в превключвателя на езика','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Преобразува превключвателя на езика в бутон, показващ другия наличен език, а не текущия.<br> Работи само когато има точно два езика – по подразбиране и превод.<br>Това засяга също превключвателя на езика shortcode и плаващия превключвател на езика.<br> За да постигнете това в превключвателя на езика в менюто, отидете на Външен вид->Менюта->Превключвател на езика и изберете Противоположен език.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Кликнете тук</a>, за да получите достъп до инструмента за оптимизация на базата данни.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Помага за премахване на възможни дублирани преводи, изчистване на ненужни данни и отстраняване на възможни проблеми с метаданните.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Тук</a> можете да видите последните 5 SQL грешки, свързани с TranslatePress, ако съществуват.','Troubleshooting'=>'Отстраняване на неизправности','Exclude Gettext strings'=>'Изключване на Gettext низове','Debug'=>'Дебъг','Custom languages'=>'Персонализирани езици','Miscellaneous options'=>'Разни настройки','Exclude strings & pages'=>'Изключване на низове и страници','Automatic Translation Memory'=>'Автоматична памет за преводи','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Използване на същия превод за подобен текст. Низовете трябва да имат 95% прилика.<br>Помага за предотвратяване на загуба на съществуващ превод при коригиране на правописни грешки или при извършване на малки промени в оригиналния текст. <br>Ако вече съществува превод за много подобен оригинален низ, той автоматично ще се използва за текущия оригинален низ.<br>Не работи при промяна на текст, който е част от блок за превод, освен ако новият текст не бъде ръчно обединен отново в блок за превод.<br>Всеки низ трябва да има минимум 50 знака.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'ВНИМАНИЕ: Тази функция може да повлияе негативно върху времето за зареждане на страниците на вторичните езици, особено при големи бази данни (например уебсайтове с много страници или продукти). Ако забележите бавно зареждане, изключете тази функция и опитайте отново.','Fix missing dynamic content'=>'Коригиране на липсващо динамично съдържание','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Може да помогне за коригиране на липсващо съдържание, вмъкнато чрез JavaScript. <br> Показва динамично вмъкнатото съдържание на оригиналния език за момент, преди заявката за превод да приключи.','Filter Gettext wrapping from post content and title'=>'Филтриране на Gettext обвивката от съдържанието и заглавието на публикацията','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Филтрира Gettext обвивката, като например #!trpst#trp-gettext, от съдържанието и заглавието на всички актуализирани публикации. Не засяга предишното съдържание. <br/><strong>Препоръчва се резервно копие на базата данни преди включване.</strong>','Filter Gettext wrapping from post meta'=>'Филтриране на Gettext обвивката от мета данните на публикацията','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Филтрира Gettext обвивката, като например #!trpst#trp-gettext, от мета данните на всички актуализирани публикации. Не засяга предишните мета данни. <br/><strong>Препоръчва се резервно копие на базата данни преди включване.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Ключ за Google Translate API','Add your API Key here...'=>'Добавете вашия API ключ тук...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Посетете <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">тази връзка</a>, за да видите как можете да създадете API ключ, <strong>да контролирате разходите за API</strong> и да зададете ограничения за HTTP реферъра.','Your HTTP referrer is: %s'=>'Вашият HTTP реферър е: %s','There was an error on the server processing your Google Translate key.'=>'Възникна грешка в сървъра при обработката на вашия Google Translate ключ.','There was an error with your Google Translate key.'=>'Възникна грешка с вашия Google Translate ключ.','Please check your TranslatePress license key.'=>'Моля, проверете вашия лицензен ключ за TranslatePress.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'Не е открит активен лиценз за този уебсайт.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'За да активирате автоматичния превод чрез TranslatePress AI, ви е необходим лицензен ключ, получен чрез създаване на безплатен акаунт.','Create your Free Account'=>'Създайте своя безплатен акаунт',' or '=>' или ','Enter your license key'=>'Въведете вашия лицензен ключ',' Or %1$spurchase one here%2$s'=>' Или %1$sкупете такъв тук%2$s','Your free account includes: '=>'Вашият безплатен акаунт включва: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'Получете повече AI думи и отключете всички AI функции с TranslatePress Pro.','You have a valid %s <strong>license</strong>.'=>'Имате валиден %s <strong>лиценз</strong>.',' words remaining. '=>' оставащи думи. ','Recheck'=>'Проверете отново','Rechecking...'=>'Проверява се отново...','Done.'=>'Готово.','Manage your license & quota on the %s'=>'Управлявайте лиценза и квотата си в %s','TranslatePress.com Account Page'=>'Страница на акаунта в TranslatePress.com','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'SEO поддръжка за slug на страницата, заглавие на страницата, описание и информация за социалния граф на Facebook и Twitter. HTML lang атрибутът е зададен правилно.','Enable Modules'=>'Активиране на модулите','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'Активирайте допълнителни модули, за да разширите TranslatePress и да подобрите функционалността на вашия преведен сайт.','More functionality with TranslatePress Pro.'=>'Още функционалност с TranslatePress Pro.','Already a Pro User?'=>'Вече сте Pro потребител?','Activate License Key'=>'Активирайте лицензния ключ','This add-on is not available on your current plan.'=>'Тази добавка не е достъпна в текущия ви план.','Continue'=>'Продължи','The link you followed has expired. Please reload the page and try again.'=>'Връзката, която последвахте, е изтекла. Моля, презаредете страницата и опитайте отново.','A valid license is required to enable Automatic Translation.'=>'Необходим е валиден лиценз, за да активирате автоматичния превод.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Manage Sites.'=>'Вашият лицензионен ключ е деактивиран за този URL. Активирайте го отново от <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Управление на сайтове.','<p><strong>License key mismatch.</strong> The license you entered doesn\'t match the TranslatePress version you have installed.</p><p>Please check that you\'ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Несъответствие на лицензионния ключ.</strong> Въведеният от вас лиценз не съответства на инсталираната версия на TranslatePress.</p><p>Моля, проверете дали сте инсталирали правилната версия за вашия лиценз от вашия TranslatePress Account.</p>','Automatically translate your website using TranslatePress AI.'=>'Автоматично преведете уебсайта си с TranslatePress AI.','In order to enable Automatic Translation using TranslatePress AI, please enter your license key from'=>'За да активирате автоматичния превод с TranslatePress AI, моля, въведете лицензионния си ключ от','your account.'=>'вашия акаунт.','Skip and continue with manual translation »'=>'Пропуснете и продължете с ръчния превод »','Get Your Free TranslatePress AI License'=>'Получете безплатен лиценз за TranslatePress AI','Generate License'=>'Генерирайте лиценз','Creating a free account includes: '=>'Създаването на безплатен акаунт включва: ','Are you a TranslatePress PRO user?'=>'Вие ли сте потребител на TranslatePress Pro?','Install & Activate your pro plugin.'=>'Инсталирайте & активирайте вашия Pro плъгин.','Skip this step'=>'Пропуснете тази стъпка','The email address you added is incorrect.'=>'Въведеният от вас имейл адрес е неправилен.','Setup Complete'=>'Настройката е завършена','You\'re ready to start translating!'=>'Готови сте да започнете да превеждате!','You have successfully set up TranslatePress for your website.'=>'Успешно настроихте TranslatePress за вашия уебсайт.','Receive '=>'Получете ','Yes, send me multilingual growth tips.'=>'Да, изпращайте ми съвети за многоезичен растеж.','Start translating'=>'Започнете превода','Sign Up and Start translating'=>'Регистрирайте се и започнете превода','Please upload a TranslatePress Pro plugin file.'=>'Моля, качете файл на приставката TranslatePress Pro.','Upload error: '=>'Грешка при качване: ','Install failed: '=>'Неуспешна инсталация: ','Plugin installed, but entry file not found. '=>'Приставката е инсталирана, но основният файл не е намерен. ','Activation error: '=>'Грешка при активиране: ','Invalid plugin specified.'=>'Посочена е невалидна приставка.','Invalid action specified.'=>'Посочено е невалидно действие.','Plugin deactivation failed.'=>'Деактивирането на приставката е неуспешно.','Plugin activation failed: '=>'Активирането на приставката е неуспешно: ','First, install and activate TranslatePress Pro'=>'Първо инсталирайте и активирайте TranslatePress Pro','Please upload the TranslatePress PRO zip archive from your'=>'Моля, качете ZIP архива на TranslatePress PRO от вашия','TranslatePress Account'=>'TranslatePress Account','Install and Activate'=>'Инсталирайте и активирайте','Installed Pro versions'=>'Инсталирани Pro версии','« Go back'=>'« Назад','Activate License »'=>'Активирайте лиценза »','You are trying to add an invalid additional language. Please select a valid option.'=>'Опитвате се да добавите невалиден допълнителен език. Моля, изберете валидна опция.','Please add an additional language.'=>'Моля, добавете допълнителен език.','You are trying to add an invalid default language. Please select a valid option.'=>'Опитвате се да добавите невалиден език по подразбиране. Моля, изберете валидна опция.','You need to select a default language.'=>'Трябва да изберете език по подразбиране.','Configure Site Languages'=>'Настройка на езиците на сайта','Select the default and additional languages for your website.'=>'Изберете езика по подразбиране и допълнителните езици за вашия сайт.','You can edit your site languages at any point.'=>'Можете да редактирате езиците на сайта си по всяко време.','Additional Language'=>'Допълнителен език','Choose a secondary language...'=>'Изберете втори език...','Add Language'=>'Добави език','Choose a language...'=>'Изберете език...','Add more than two languages with TranslatePress Pro.'=>'Добавете повече от два езика с TranslatePress Pro.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Manage Sites.'=>'Вашият лицензионен ключ е деактивиран за този URL. Активирайте го отново от <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Управление на сайтове.','Add your License Key'=>'Добавете вашия лицензионен ключ','Add your License Key to unlock all premium features. Find the License Key in your'=>'Добавете вашия лицензионен ключ, за да отключите всички премиум функции. Намерете лицензионния ключ във вашия','Your license is valid and active.'=>'Вашият лиценз е валиден и активен.','« Go Back'=>'« Назад','Set up Language Switcher'=>'Настройка на превключвателя за език','Select the style of the language switcher. You will find more ways to display it, in plugin settings.'=>'Изберете стила на превключвателя за език. Ще намерите още начини за показването му в настройките на приставката.','Displays a small language drop-down across your website, in a corner of your choosing.'=>'Показва малко падащо меню за език в целия ви уебсайт, в ъгъл по ваш избор.','Switcher Location'=>'Местоположение на превключвателя','Apply a Template'=>'Приложи шаблон','You can customize the design later'=>'Можете да персонализирате дизайна по-късно','Default Template'=>'Шаблон по подразбиране','Dark Template'=>'Тъмен шаблон','Border Template'=>'Шаблон с рамка','Border'=>'Рамка','Transparent Template'=>'Прозрачен шаблон','Transparent'=>'Прозрачен','Welcome to TranslatePress'=>'Добре дошли в TranslatePress','Quick guided setup to configure TranslatePress in no time!'=>'Бърза водена настройка за конфигуриране на TranslatePress за нула време!','It takes less than a minute.'=>'Отнема по-малко от минута.','Scanning item %1$d of %2$d...'=>'Сканиране на елемент %1$d от %2$d...','Manually translated'=>'Ръчно преведено','Automatically translated'=>'Автоматично преведено','Not translated'=>'Непреведено','Bulk Actions'=>'Масови действия','Delete entries'=>'Изтриване на записи','Edit'=>'Редактирай','Delete'=>'Изтрий','Filter'=>'Филтрирай','Clear filters'=>'Изчисти филтрите','Add New'=>'Добави нов','Rescan plugins and theme for strings'=>'Повторно сканиране на добавките и темата за низове','Scanning plugins and theme for strings...'=>'Сканиране на добавките и темата за низове...','Plugins and theme scan is complete'=>'Сканирането на добавките и темата е завършено','Plugins and theme scan did not finish due to an error'=>'Сканирането на добавките и темата не завърши поради грешка','Import / Export'=>'Импорт / Експорт','items'=>'елементи','See More'=>'Виж още','See Less'=>'Виж по-малко','Apply'=>'Приложи','No strings match your query.'=>'Няма низове, отговарящи на вашето търсене.','Try to rescan plugins and theme for strings.'=>'Опитайте да сканирате отново добавките и темата за низове.','An error occurred while loading results. Most likely you were logged out. Reload page?'=>'Възникна грешка при зареждане на резултатите. Най-вероятно сте излезли от профила си. Да се презареди ли страницата?','found in translation'=>'намерено в превода','Select All'=>'Избери всички','Select Visible'=>'Избери видимите','You are about to perform this action on all the strings matching your filter, not just the visibly checked. To perform the action only to the visible strings click "Select Visible" from the table header dropdown.'=>'На път сте да извършите това действие върху всички низове, отговарящи на вашия филтър, не само върху видимо отметнатите. За да извършите действието само върху видимите низове, щракнете върху "Избери видимите" от падащото меню в заглавието на таблицата.','You are about to perform this action only on the visible strings. To perform the action on all the strings matching the filter click "Select All" from the table header dropdown.'=>'На път сте да извършите това действие само върху видимите низове. За да извършите действието върху всички низове, отговарящи на филтъра, щракнете върху "Избери всички" от падащото меню в заглавието на таблицата.','To continue please type the word:'=>'За да продължите, въведете думата:','The word typed was incorrect. Action was cancelled.'=>'Въведената дума е грешна. Действието беше отменено.','Warning: This action cannot be undone. Deleting a string will remove its current translation. The original string will appear again in this interface after TranslatePress detects it. This action is NOT equivalent to excluding the string from being translated again.'=>'Внимание: Това действие не може да бъде отменено. Изтриването на низ ще премахне текущия му превод. Оригиналният низ ще се появи отново в този интерфейс, след като TranslatePress го открие. Това действие НЕ е еквивалентно на изключване на низа от повторно превеждане.','%d original entries and their translations were deleted.'=>'Бяха изтрити %d оригинални записа и техните преводи.','Navigate to next page'=>'Навигиране към следващата страница','Navigate to previous page'=>'Навигиране към предишната страница','Navigate to first page'=>'Навигиране към първата страница','Navigate to last page'=>'Навигиране към последната страница','Type a page number to navigate to'=>'Въведете номер на страница, към която да навигирате','Incorrect page number. Type a page number between 1 and total number of pages'=>'Грешен номер на страница. Въведете номер на страница между 1 и общия брой страници','Search original and translated strings containing typed keywords while also matching selected filters. Place string in quotes for exact match: "string"'=>'Търсене на оригинални и преведени низове, съдържащи въведените ключови думи и отговарящи на избраните филтри. Поставете низа в кавички за точно съвпадение: "низ"','Filter strings according to selected translation status, filters and keywords and selected filters'=>'Филтриране на низовете според избраното състояние на превода, филтрите и ключовите думи и избраните филтри','Removes selected filters'=>'Премахва избраните филтри','See options for selecting all strings'=>'Вижте опциите за избиране на всички низове','Click to sort strings by this column'=>'Щракнете, за да сортирате низовете по тази колона','Language in which the translation status filter applies. Leave unselected for the translation status to apply to ANY language'=>'Език, към който се прилага филтърът за състояние на превода. Оставете неизбран, за да се прилага състоянието на превода ЗА ВСЕКИ ЕЗИК','Search'=>'Търсене','Slugs that are not found in either one of the other categories.'=>'Slug-ове, които не се намират в нито една от другите категории.','Plugins and Theme String Translation'=>'Превод на низове от добавки и тема','Gettext'=>'Gettext','Search Gettext Strings'=>'Търсене на Gettext низове','ID'=>'ID','Original String'=>'Оригинален низ','Translation'=>'Превод','Filter by domain'=>'Филтриране по домейн','Filter by type'=>'Филтриране по тип','Email text'=>'Текст на имейла','Emails String Translation'=>'Превод на имейл низове','Emails'=>'Имейли','Search Email Strings'=>'Търсене на имейл низове','User Inputted String Translation'=>'Превод на потребителски низове','Regular'=>'Обикновени','Search Regular Strings'=>'Търсене на обикновени низове','Filter by Translation Block'=>'Филтриране по блок за превод','URL Slugs Translation'=>'Превод на URL slug-ове','String Translation Editor'=>'Редактор за превод на низове','TranslatePress has detected and cleaned up some failed translation entries in your database following %1$san isolated incident%2$s. No further action is required.'=>'TranslatePress откри и изчисти някои неуспешни записи за превод във вашата база данни след %1$sизолиран инцидент%2$s. Не са необходими допълнителни действия.','Post Slug'=>'Slug на публикацията','Invalid language code'=>'Невалиден езиков код','First by browser language, then IP address (recommended)'=>'Първо по езика на браузъра, след това по IP адрес (препоръчително)','First by IP address, then by browser language'=>'Първо по IP адрес, след това по езика на браузъра','Only by browser language'=>'Само по езика на браузъра','Only by IP address'=>'Само по IP адрес','A popup appears asking the user if they want to be redirected'=>'Появява се изскачащ прозорец, който пита потребителя дали иска да бъде пренасочен','Redirect directly (*not recommended)'=>'Директно пренасочване (*не се препоръчва)','Pop-up window over the content'=>'Изскачащ прозорец върху съдържанието','Hello bar before the content'=>'Лента за известия преди съдържанието','WARNING. Cannot determine your language preference based on your current IP.<br>This is most likely because the website is on a local environment.'=>'ВНИМАНИЕ. Не може да се определи езиковото ви предпочитание въз основа на текущия ви IP адрес.<br>Това най-вероятно е, защото уебсайтът е в локална среда.','Go to <a href="%s" target="_self">Advanced</a> tab to change this feature\'s settings'=>'Отидете в раздела <a href="%s" target="_self">Разширени</a>, за да промените настройките на тази функция.','User Language Detection Method'=>'Метод за откриване на езика на потребителя','Select how the language should be detected for first time visitors.<br>The visitor\'s last displayed language will be remembered through cookies.'=>'Изберете как езикът да се открива за посетители за първи път.<br>Последно показаният език на посетителя ще бъде запомнен чрез бисквитки.','User Notification Popup'=>'Изскачащ прозорец за известяване на потребителя','A popup appears asking the user if they want to be redirected.'=>'Появява се изскачащ прозорец, който пита потребителя дали иска да бъде пренасочен.','Popup Type'=>'Тип на изскачащия прозорец','Popup Text'=>'Текст на изскачащия прозорец','The same text is displayed in all languages. <br>A selecting language switcher will be appended to the pop-up. The detected language is pre-selected.'=>'Един и същ текст се показва на всички езици.<br>Към изскачащия прозорец ще бъде добавен превключвател за избор на език. Откритият език е предварително избран.','Button Text'=>'Текст на бутона','Write the text you wish to appear on the button..'=>'Напишете текста, който искате да се показва на бутона..','Close Button Text'=>'Текст на бутона за затваряне','Write the text you wish to appear on the close button. Leave empty for just the close button.'=>'Напишете текста, който искате да се показва на бутона за затваряне. Оставете празно, за да се покаже само бутонът за затваряне.','Bad request. There was an error accessing the DeepL API.'=>'Грешна заявка. Възникна грешка при достъпа до DeepL API.','The API key entered is invalid.'=>'Въведеният API ключ е невалиден.','The API resource could not be found.'=>'API ресурсът не беше намерен.','The request size is too large.'=>'Размерът на заявката е твърде голям.','The request is too long.'=>'Заявката е твърде дълга.','Too many requests. Please try again later.'=>'Твърде много заявки. Моля, опитайте отново по-късно.','Your translation quota has been reached.'=>'Вашата квота за превод е изчерпана.','We could not process your request. Please try again later.'=>'Не можахме да обработим вашата заявка. Моля, опитайте отново по-късно.','There is an error on the DeepL service and your request could not be processed.'=>'Има грешка в услугата DeepL и вашата заявка не можа да бъде обработена.','DeepL API Type'=>'Тип DeepL API','Pro'=>'Про','Free'=>'Безплатен','Select the type of DeepL API you want to use.'=>'Изберете типа DeepL API, който искате да използвате.','DeepL API Key'=>'DeepL API ключ','Visit <a href="%s" target="_blank">this link</a> to see how you can set up an API key and control API costs.'=>'Посетете <a href="%s" target="_blank">тази връзка</a>, за да видите как можете да настроите API ключ и да контролирате API разходите.','Translator'=>'Преводач',' TranslatePress Settings'=>' Настройки на TranslatePress','Allow this user to translate the website.'=>'Позволете на този потребител да превежда уебсайта.','(inactive)'=>'(неактивен)','Taxonomy Slugs'=>'Slug-ове на таксономии','Search Taxonomy Slugs'=>'Търсене на slug-ове на таксономии','Taxonomy Slug'=>'Slug на таксономията','Term Slugs'=>'Slug-ове на термини','Search Term Slugs'=>'Търсене на slug-ове на термини','Term Slug'=>'Slug на термина','Taxonomy'=>'Таксономия','Filter by Taxonomy'=>'Филтриране по таксономия','Post Slugs'=>'Slug-ове на публикации','Search Post Slugs'=>'Търсене на slug-ове на публикации','Post ID'=>'ID на публикацията','Post Type'=>'Тип публикация','Filter by Post Type'=>'Филтриране по тип публикация','Published'=>'Публикувано','Any Post Status'=>'Всякакъв статус на публикацията','Post Type Base Slugs'=>'Базови slug-ове за тип публикация','Post Type Base Slug'=>'Базов slug за тип публикация','Search Post Type Base Slugs'=>'Търсене на базови slug-ове за тип публикация','WooCommerce Slugs'=>'WooCommerce slug-ове','WooCommerce Slug'=>'WooCommerce slug','Search WooCommerce Slugs'=>'Търсене на WooCommerce slug-ове','Other Slugs'=>'Други slug-ове','Search Other Slugs'=>'Търсене на други slug-ове','Verbiage for the DeepL Pro Add-onTranslatePress Pro Add-on'=>'TranslatePress Pro Add-on','Verbiage for the DeepL Pro Add-onAddons tab'=>'Раздел Добавки','page 1 of 3of'=>'/','Untranslated in this languagein'=>'в']];